output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?festival ?festivalLabel ?city ?cityLabel WHERE {
  ?country wdt:P31 wd:Q6256 ; wdt:P30 wd:Q46 ; wdt:P36 ?city .
  ?festival wdt:P31 wd:Q218529 ; wdt:P276 ?city .
  OPTIONAL {
    ?festival rdfs:label ?festivalLabel .
    FILTER(LANG(?festivalLabel) = "en")
  }
  OPTIONAL {
    ?city rdfs:label ?cityLabel .
    FILTER(LANG(?cityLabel) = "en")
  }
}
